diff --git a/llvm/lib/Analysis/InstructionSimplify.cpp b/llvm/lib/Analysis/InstructionSimplify.cpp
index 3f3f6c6e0d1a..fe08ddc7d348 100644
--- a/llvm/lib/Analysis/InstructionSimplify.cpp
+++ b/llvm/lib/Analysis/InstructionSimplify.cpp
@@ -4545,6 +4545,7 @@ static Value *simplifySelectWithFCmp(Value *Cond, Value *T, Value *F,

 /// Given operands for a SelectInst, see if we can fold the result.
 /// If not, this returns null.
+
 static Value *simplifySelectInst(Value *Cond, Value *TrueVal, Value *FalseVal,
                                  const SimplifyQuery &Q, unsigned MaxRecurse) {
   if (auto *CondC = dyn_cast<Constant>(Cond)) {
@@ -4630,6 +4631,32 @@ static Value *simplifySelectInst(Value *Cond, Value *TrueVal, Value *FalseVal,
       return ConstantInt::getFalse(Cond->getType());
   }

+  // If the condition is a select with false as the false value, and the outer
+  // select has true as the true value and the condition's true value as the
+  // false value, simplify to the condition's true value.
+  // select (select X, Y, false), true, Y --> Y
+  // Similarly, if the condition is a select with true as the true value, and
+  // the outer select has false as the false value and the condition's false
+  // value as the true value, simplify to the condition's false value.
+  // select (select X, true, Y), Y, false --> Y
+  Value *X, *Y;
+  if (match(Cond, m_Select(m_Value(X), m_Value(Y), m_ZeroInt())) &&
+      match(TrueVal, m_One()) && FalseVal == Y)
+    return Y;
+  if (match(Cond, m_Select(m_Value(X), m_One(), m_Value(Y))) &&
+      match(FalseVal, m_ZeroInt()) && TrueVal == Y)
+    return Y;
+
+  // Generalize to handle logical AND/OR directly.
+  // select (and X, Y), true, Y --> Y
+  if (match(Cond, m_c_And(m_Value(X), m_Value(Y))) &&
+      match(TrueVal, m_One()) && FalseVal == Y)
+    return Y;
+  // select (or X, Y), X, false --> X
+  if (match(Cond, m_c_Or(m_Value(X), m_Value(Y))) &&
+      TrueVal == X && match(FalseVal, m_ZeroInt()))
+    return X;
+
   // If the true or false value is poison, we can fold to the other value.
   // If the true or false value is undef, we can fold to the other value as
   // long as the other value isn't poison.
@@ -4695,6 +4722,7 @@ static Value *simplifySelectInst(Value *Cond, Value *TrueVal, Value *FalseVal,
   return nullptr;
 }

+
 Value *llvm::simplifySelectInst(Value *Cond, Value *TrueVal, Value *FalseVal,
                                 const SimplifyQuery &Q) {
   return ::simplifySelectInst(Cond, TrueVal, FalseVal, Q, RecursionLimit);

